import React, { useState, useEffect } from 'react';
import { StyleSheet, View, Text, ScrollView, TouchableOpacity, TextInput, Alert, Share } from 'react-native';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons } from '@expo/vector-icons';
import * as Print from 'expo-print';
import * as Sharing from 'expo-sharing';
import { useAuth } from '../context/AuthContext';
import { useTheme } from '../theme/ThemeContext';
import { AgronomistService } from '../services/AgronomistService';
import { RecommendationService } from '../services/RecommendationService';
import { executeQuery } from '../database/database';
import Card from '../components/common/Card';
import AgroButton from '../components/common/AgroButton';

const COMMON_PRODUCTS = [
    'NITRATO DE CÁLCIO', 'MAP (FOSFATO MONOAMÔNICO)', 'SULFATO DE MAGNÉSIO', 
    'CLORETO DE POTÁSSIO', 'URÉIA', 'ÁCIDO FOSFÓRICO', 'BORO (SULFATO DE BORO)', 
    'SULFATO DE ZINCO', 'NITRATO DE POTÁSSIO', 'QUELATO DE FERRO'
];

export default function CreateRecommendationScreen({ navigation }) {
    const { theme } = useTheme();
    const { user } = useAuth();

    const [loading, setLoading] = useState(false);
    const [clients, setClients] = useState([]);
    const [plantings, setPlantings] = useState([]);
    
    // Form fields
    const [selectedClient, setSelectedClient] = useState(null);
    const [selectedPlanting, setSelectedPlanting] = useState(null);
    const [globalProducts, setGlobalProducts] = useState(COMMON_PRODUCTS);
    const [focusedRowId, setFocusedRowId] = useState(null);
    const [activeTab, setActiveTab] = useState('GOTEJO'); // GOTEJO ou FOLIAR
    const [recipeRows, setRecipeRows] = useState([
        { id: '1', product: '', dosage: '', unit: 'KG', baseQty: '100', baseUnit: 'LT' }
    ]);
    const [notes, setNotes] = useState('');
    const [submitting, setSubmitting] = useState(false);

    // Modal selectors
    const [showClientModal, setShowClientModal] = useState(false);
    const [showPlantingModal, setShowPlantingModal] = useState(false);

    useEffect(() => {
        loadClients();
        loadProducts();
    }, []);

    const loadProducts = async () => {
        try {
            const res = await executeQuery("SELECT nome FROM cadastro WHERE is_deleted = 0 AND (tipo = 'INSUMO' OR estocavel = 1)");
            const dbProducts = [];
            for (let i = 0; i < res.rows.length; i++) {
                if (res.rows.item(i).nome) dbProducts.push(res.rows.item(i).nome.toUpperCase());
            }
            const merged = Array.from(new Set([...COMMON_PRODUCTS, ...dbProducts]));
            setGlobalProducts(merged);
        } catch (e) {
            console.log("Erro ao carregar produtos:", e);
        }
    };

    const loadClients = async () => {
        setLoading(true);
        try {
            const activeLinks = await AgronomistService.getActiveLinks(user.uuid, 'AGRONOMO');
            setClients(activeLinks);
        } catch (e) {
            console.log(e);
        } finally {
            setLoading(false);
        }
    };

    const handleSelectClient = async (client) => {
        setSelectedClient(client);
        setSelectedPlanting(null);
        setShowClientModal(false);

        // Carrega plantios desse cliente de forma remota/local
        try {
            // Em cenários offline-first, buscamos plantios do cliente
            const res = await executeQuery('SELECT * FROM plantio WHERE is_deleted = 0 ORDER BY data DESC');
            const rows = [];
            for (let i = 0; i < res.rows.length; i++) {
                rows.push(res.rows.item(i));
            }
            setPlantings(rows);
        } catch (e) {
            console.log(e);
        }
    };

    const handleAddRow = () => {
        const newId = (recipeRows.length + 1).toString();
        setRecipeRows([...recipeRows, { id: newId, product: '', dosage: '', unit: 'KG', baseQty: '100', baseUnit: 'LT' }]);
    };

    const handleRemoveRow = (id) => {
        if (recipeRows.length === 1) return;
        setRecipeRows(recipeRows.filter(r => r.id !== id));
    };

    const handleRowChange = (id, field, value) => {
        setRecipeRows(recipeRows.map(row => {
            if (row.id === id) {
                return { ...row, [field]: value };
            }
            return row;
        }));
    };

    const generatePDF = async (recipeData) => {
        try {
            const htmlContent = `
                <html>
                <head>
                    <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, minimum-scale=1.0, user-scalable=no" />
                    <style>
                        body { font-family: 'Helvetica', sans-serif; padding: 20px; color: #333; }
                        .header { text-align: center; border-bottom: 2px solid #10B981; padding-bottom: 10px; margin-bottom: 20px; }
                        .title { color: #064E3B; font-size: 24px; font-weight: bold; margin: 0; }
                        .subtitle { color: #666; font-size: 14px; margin-top: 5px; }
                        .info-section { display: flex; justify-content: space-between; margin-bottom: 20px; background: #F3F4F6; padding: 15px; border-radius: 8px; }
                        .info-block p { margin: 5px 0; font-size: 14px; }
                        table { width: 100%; border-collapse: collapse; margin-bottom: 20px; }
                        th { background-color: #10B981; color: white; text-align: left; padding: 12px; font-size: 14px; }
                        td { padding: 12px; border-bottom: 1px solid #E5E7EB; font-size: 14px; }
                        tr:nth-child(even) { background-color: #F9FAFB; }
                        .notes { background: #FEF3C7; border-left: 4px solid #F59E0B; padding: 15px; font-size: 14px; margin-bottom: 40px; }
                        .footer { margin-top: 50px; text-align: center; }
                        .signature-line { width: 250px; border-top: 1px solid #333; margin: 0 auto 10px auto; }
                        .footer-text { font-size: 12px; color: #666; }
                        .watermark { font-size: 10px; color: #9CA3AF; margin-top: 20px; }
                    </style>
                </head>
                <body>
                    <div class="header">
                        <h1 class="title">RECEITUÁRIO AGRONÔMICO</h1>
                        <p class="subtitle">Prescrição Técnica Oficial</p>
                    </div>
                    
                    <div class="info-section">
                        <div class="info-block">
                            <p><strong>Produtor:</strong> ${selectedClient.client_name}</p>
                            <p><strong>Talhão/Cultura:</strong> ${selectedPlanting ? selectedPlanting.cultura + ' (' + selectedPlanting.tipo_plantio + ')' : 'Não informado'}</p>
                            <p><strong>Data de Emissão:</strong> ${new Date().toLocaleDateString('pt-BR')}</p>
                        </div>
                        <div class="info-block">
                            <p><strong>Resp. Técnico:</strong> ${user.name || 'Engenheiro Agrônomo'}</p>
                            <p><strong>Método de Aplicação:</strong> Via ${activeTab}</p>
                        </div>
                    </div>

                    <table>
                        <thead>
                            <tr>
                                <th>Item</th>
                                <th>Produto (Insumo)</th>
                                <th>Dose Recomendada</th>
                            </tr>
                        </thead>
                        <tbody>
                            ${recipeData.map((r, index) => `
                                <tr>
                                    <td>#${index + 1}</td>
                                    <td><strong>${r.product}</strong></td>
                                    <td>${r.dosage} ${r.unit} <span style="color:#666; font-size:12px;">/ ${r.baseQty} ${r.baseUnit}</span></td>
                                </tr>
                            `).join('')}
                        </tbody>
                    </table>

                    <div class="notes">
                        <strong>Observações Técnicas:</strong><br/>
                        ${notes.trim() ? notes.replace(/\n/g, '<br/>') : 'Nenhuma observação adicional.'}
                    </div>

                    <div class="footer">
                        <div class="signature-line"></div>
                        <p class="footer-text"><strong>${user.name || 'Engenheiro Agrônomo'}</strong></p>
                        <p class="footer-text">Assinatura do Responsável</p>
                        <p class="watermark">Gerado digitalmente pelo sistema AgroGB</p>
                    </div>
                </body>
                </html>
            `;

            const { uri } = await Print.printToFileAsync({ html: htmlContent });
            await Sharing.shareAsync(uri, { UTI: '.pdf', mimeType: 'application/pdf', dialogTitle: 'Compartilhar Receituário PDF' });
        } catch (error) {
            console.error("Erro ao gerar PDF:", error);
            Alert.alert("Erro", "Não foi possível gerar o PDF.");
        }
    };

    const handlePublish = async () => {
        if (!selectedClient) {
            return Alert.alert('Atenção', 'Selecione o cliente produtor.');
        }

        const invalidRow = recipeRows.find(r => !r.product.trim() || !r.dosage.trim());
        if (invalidRow) {
            return Alert.alert('Atenção', 'Preencha o nome do produto e a dosagem em todas as linhas da receita.');
        }

        setSubmitting(true);
        try {
            const recipeData = recipeRows.map(r => ({
                product: r.product.toUpperCase().trim(),
                dosage: parseFloat(r.dosage) || 0,
                unit: r.unit,
                baseQty: parseFloat(r.baseQty) || 100,
                baseUnit: r.baseUnit
            }));

            const payload = {
                agronomist_id: user.uuid,
                client_id: selectedClient.client_id,
                planting_id: selectedPlanting ? selectedPlanting.uuid : null,
                recipe_type: activeTab,
                recipe_data: recipeData,
                notes: notes.trim(),
                status: 'PENDING'
            };

            const res = await RecommendationService.createRecommendation(payload);
            if (res.success) {
                const recipeText = recipeData.map(r => `🔹 ${r.product} - ${r.dosage}${r.unit} p/ cada ${r.baseQty}${r.baseUnit}`).join('\n');
                const shareMessage = `🌱 *Prescrição Agronômica - AgroGB*\n*Cliente:* ${selectedClient.client_name}\n\n💧 *Método:* Via ${activeTab}\n\n*Produtos e Dosagens:*\n${recipeText}\n\n*Recomendação:* ${notes.trim() || 'Nenhuma'}\n\n📱 Gerado com AgroGB - Gestão Inteligente`;

                Alert.alert('🎉 Emitido!', 'Prescrição técnica salva com sucesso.', [
                    { text: 'PDF 📄', onPress: () => {
                        generatePDF(recipeData);
                        navigation.goBack();
                    }},
                    { text: 'WHATSAPP 🟢', onPress: async () => {
                        try {
                            await Share.share({ message: shareMessage });
                        } catch (error) {
                            console.log(error);
                        }
                        navigation.goBack();
                    }},
                    { text: 'SAIR', onPress: () => navigation.goBack() }
                ]);
            } else {
                Alert.alert('Erro', res.error || 'Erro ao publicar recomendação.');
            }
        } catch (err) {
            Alert.alert('Erro', 'Ocorreu uma falha ao enviar.');
        } finally {
            setSubmitting(false);
        }
    };

    return (
        <View style={styles.container}>
            <LinearGradient colors={['#064E3B', '#10B981']} style={styles.header}>
                <TouchableOpacity onPress={() => navigation.goBack()} style={styles.backBtn}>
                    <Ionicons name="arrow-back" size={24} color="#FFF" />
                </TouchableOpacity>
                <Text style={styles.title}>NOVA PRESCRIÇÃO</Text>
                <Text style={styles.subtitle}>Elabore receitas rígidas de adubação.</Text>
            </LinearGradient>

            <ScrollView contentContainerStyle={styles.scroll} showsVerticalScrollIndicator={false}>
                
                {/* 1. SELETOR DE CLIENTE */}
                <Text style={styles.sectionHeader}>PRODUTOR DESTINATÁRIO *</Text>
                <TouchableOpacity 
                    style={styles.selector} 
                    onPress={() => setShowClientModal(true)}
                    activeOpacity={0.8}
                >
                    <View style={styles.selectorInner}>
                        <Ionicons name="people" size={20} color="#10B981" />
                        <Text style={[styles.selectorText, selectedClient && styles.selectorTextSelected]}>
                            {selectedClient ? selectedClient.client_name : 'Selecione o Cliente'}
                        </Text>
                    </View>
                    <Ionicons name="chevron-down" size={20} color="#9CA3AF" />
                </TouchableOpacity>

                {/* 2. SELETOR DE PLANTIO / TALHÃO */}
                {selectedClient && (
                    <>
                        <Text style={styles.sectionHeader}>TALHÃO / CULTURA DO CLIENTE (OPCIONAL)</Text>
                        <TouchableOpacity 
                            style={styles.selector} 
                            onPress={() => setShowPlantingModal(true)}
                            activeOpacity={0.8}
                        >
                            <View style={styles.selectorInner}>
                                <Ionicons name="leaf" size={20} color="#10B981" />
                                <Text style={[styles.selectorText, selectedPlanting && styles.selectorTextSelected]}>
                                    {selectedPlanting ? `${selectedPlanting.cultura.toUpperCase()} (${selectedPlanting.tipo_plantio})` : 'Selecione o Talhão / Cultura'}
                                </Text>
                            </View>
                            <Ionicons name="chevron-down" size={20} color="#9CA3AF" />
                        </TouchableOpacity>
                    </>
                )}

                {/* 3. TIPO DE ADUBAÇÃO (TABS) */}
                <Text style={styles.sectionHeader}>MÉTODO DE APLICAÇÃO *</Text>
                <View style={styles.tabContainer}>
                    <TouchableOpacity 
                        style={[styles.tab, activeTab === 'GOTEJO' && styles.tabActive]}
                        onPress={() => setActiveTab('GOTEJO')}
                    >
                        <Ionicons name="water" size={18} color={activeTab === 'GOTEJO' ? '#FFF' : '#10B981'} />
                        <Text style={[styles.tabText, activeTab === 'GOTEJO' && styles.tabTextActive]}>ADUBAÇÃO GOTEJO</Text>
                    </TouchableOpacity>
                    
                    <TouchableOpacity 
                        style={[styles.tab, activeTab === 'FOLIAR' && styles.tabActive]}
                        onPress={() => setActiveTab('FOLIAR')}
                    >
                        <Ionicons name="leaf" size={18} color={activeTab === 'FOLIAR' ? '#FFF' : '#10B981'} />
                        <Text style={[styles.tabText, activeTab === 'FOLIAR' && styles.tabTextActive]}>ADUBAÇÃO FOLIAR</Text>
                    </TouchableOpacity>
                </View>

                {/* 4. TABELA DE PRODUTOS DINÂMICA */}
                <View style={styles.recipeHeaderRow}>
                    <Text style={styles.sectionHeader}>PRODUTOS E DOSAGEM *</Text>
                    <TouchableOpacity style={styles.addRowBtn} onPress={handleAddRow}>
                        <Ionicons name="add-circle" size={18} color="#10B981" />
                        <Text style={styles.addRowText}>ADICIONAR</Text>
                    </TouchableOpacity>
                </View>

                <View style={{ gap: 12 }}>
                    {recipeRows.map((row, idx) => (
                        <Card key={row.id} style={styles.rowCard}>
                            <View style={styles.rowTop}>
                                <Text style={styles.rowNumber}>Insumo #{idx + 1}</Text>
                                {recipeRows.length > 1 && (
                                    <TouchableOpacity onPress={() => handleRemoveRow(row.id)}>
                                        <Ionicons name="trash-outline" size={18} color="#EF4444" />
                                    </TouchableOpacity>
                                )}
                            </View>

                            <TextInput 
                                style={styles.inputField}
                                placeholder="Nome do Produto (Ex: Nitrato de Cálcio)"
                                placeholderTextColor="#9CA3AF"
                                value={row.product}
                                onChangeText={v => handleRowChange(row.id, 'product', v)}
                                onFocus={() => setFocusedRowId(row.id)}
                                onBlur={() => setTimeout(() => setFocusedRowId(null), 200)}
                            />

                            {focusedRowId === row.id && row.product.length > 0 && (
                                <ScrollView horizontal showsHorizontalScrollIndicator={false} style={styles.suggestionsContainer}>
                                    {globalProducts.filter(p => p.includes(row.product.toUpperCase())).slice(0, 5).map(p => (
                                        <TouchableOpacity 
                                            key={p} 
                                            style={styles.suggestionChip}
                                            onPress={() => {
                                                handleRowChange(row.id, 'product', p);
                                                setFocusedRowId(null);
                                            }}
                                        >
                                            <Text style={styles.suggestionText}>{p}</Text>
                                        </TouchableOpacity>
                                    ))}
                                </ScrollView>
                            )}

                            <View style={styles.rowFields}>
                                <TextInput 
                                    style={[styles.inputField, { flex: 2 }]}
                                    placeholder="Dose (Ex: 10)"
                                    placeholderTextColor="#9CA3AF"
                                    keyboardType="numeric"
                                    value={row.dosage}
                                    onChangeText={v => handleRowChange(row.id, 'dosage', v)}
                                />
                                
                                <View style={styles.unitSelector}>
                                    {['KG', 'GR', 'LT', 'ML', 'MG'].map(u => (
                                        <TouchableOpacity 
                                            key={u}
                                            style={[styles.unitBtn, row.unit === u && styles.unitBtnActive]}
                                            onPress={() => handleRowChange(row.id, 'unit', u)}
                                        >
                                            <Text style={[styles.unitBtnText, row.unit === u && styles.unitBtnTextActive]}>{u}</Text>
                                        </TouchableOpacity>
                                    ))}
                                </View>
                            </View>

                            <View style={[styles.rowFields, { marginTop: -4 }]}>
                                <TextInput 
                                    style={[styles.inputField, { flex: 2 }]}
                                    placeholder="Para cada (Base: 100)"
                                    placeholderTextColor="#9CA3AF"
                                    keyboardType="numeric"
                                    value={row.baseQty}
                                    onChangeText={v => handleRowChange(row.id, 'baseQty', v)}
                                />
                                
                                <View style={styles.unitSelector}>
                                    {['LT', 'HA', 'PÉS'].map(u => (
                                        <TouchableOpacity 
                                            key={u}
                                            style={[styles.unitBtn, row.baseUnit === u && styles.unitBtnActive]}
                                            onPress={() => handleRowChange(row.id, 'baseUnit', u)}
                                        >
                                            <Text style={[styles.unitBtnText, row.baseUnit === u && styles.unitBtnTextActive]}>{u}</Text>
                                        </TouchableOpacity>
                                    ))}
                                </View>
                            </View>
                        </Card>
                    ))}
                </View>

                {/* 5. OBSERVAÇÕES TÉCNICAS */}
                <Text style={styles.sectionHeader}>RECOMENDAÇÕES ADICIONAIS & OBSERVAÇÕES</Text>
                <TextInput 
                    style={styles.notesInput}
                    placeholder="Escreva recomendações extras (Ex: pH da água, intervalo de aplicação, etc.)"
                    placeholderTextColor="#9CA3AF"
                    multiline
                    numberOfLines={4}
                    value={notes}
                    onChangeText={setNotes}
                />

                <View style={{ marginTop: 20 }}>
                    <AgroButton 
                        title="EMITIR E ENVIAR PRESCRIÇÃO"
                        onPress={handlePublish}
                        loading={submitting}
                    />
                </View>

            </ScrollView>

            {/* CLIENT MODAL SELECTOR */}
            {showClientModal && (
                <View style={styles.modalOverlay}>
                    <Card style={styles.modalCard}>
                        <View style={styles.modalHeader}>
                            <Text style={styles.modalTitle}>Selecione o Cliente</Text>
                            <TouchableOpacity onPress={() => setShowClientModal(false)}>
                                <Ionicons name="close" size={24} color="#374151" />
                            </TouchableOpacity>
                        </View>
                        <ScrollView style={styles.modalList} showsVerticalScrollIndicator={false}>
                            {clients.length === 0 ? (
                                <Text style={styles.modalEmptyText}>Nenhum cliente produtor vinculado.</Text>
                            ) : (
                                clients.map(c => (
                                    <TouchableOpacity 
                                        key={c.uuid}
                                        style={styles.modalItem}
                                        onPress={() => handleSelectClient(c)}
                                    >
                                        <Ionicons name="person-outline" size={20} color="#10B981" />
                                        <Text style={styles.modalItemText}>{c.client_name}</Text>
                                    </TouchableOpacity>
                                ))
                            )}
                        </ScrollView>
                    </Card>
                </View>
            )}

            {/* PLANTING MODAL SELECTOR */}
            {showPlantingModal && (
                <View style={styles.modalOverlay}>
                    <Card style={styles.modalCard}>
                        <View style={styles.modalHeader}>
                            <Text style={styles.modalTitle}>Selecione o Talhão / Cultura</Text>
                            <TouchableOpacity onPress={() => setShowPlantingModal(false)}>
                                <Ionicons name="close" size={24} color="#374151" />
                            </TouchableOpacity>
                        </View>
                        <ScrollView style={styles.modalList} showsVerticalScrollIndicator={false}>
                            {plantings.length === 0 ? (
                                <Text style={styles.modalEmptyText}>Nenhum plantio ativo registrado para o cliente.</Text>
                            ) : (
                                plantings.map(p => (
                                    <TouchableOpacity 
                                        key={p.uuid}
                                        style={styles.modalItem}
                                        onPress={() => {
                                            setSelectedPlanting(p);
                                            setShowPlantingModal(false);
                                        }}
                                    >
                                        <Ionicons name="leaf-outline" size={20} color="#10B981" />
                                        <Text style={styles.modalItemText}>{p.cultura.toUpperCase()} ({p.tipo_plantio})</Text>
                                    </TouchableOpacity>
                                ))
                            )}
                        </ScrollView>
                    </Card>
                </View>
            )}
        </View>
    );
}

const styles = StyleSheet.create({
    container: { flex: 1, backgroundColor: '#F3F4F6' },
    header: { paddingTop: 60, paddingBottom: 35, paddingHorizontal: 25, borderBottomLeftRadius: 35, borderBottomRightRadius: 35 },
    backBtn: { marginBottom: 15 },
    title: { color: '#FFF', fontSize: 20, fontWeight: '900', letterSpacing: 2 },
    subtitle: { color: 'rgba(255,255,255,0.85)', fontSize: 13, marginTop: 5, fontWeight: '600' },
    scroll: { padding: 20, paddingBottom: 100 },
    
    sectionHeader: { fontSize: 11, fontWeight: '900', color: '#6B7280', letterSpacing: 1.5, marginBottom: 10, marginTop: 15 },
    
    /* Selector fields */
    selector: { flexDirection: 'row', alignItems: 'center', justifyContent: 'space-between', backgroundColor: '#FFF', paddingVertical: 16, paddingHorizontal: 20, borderRadius: 15, borderWidth: 1.5, borderColor: '#E5E7EB' },
    selectorInner: { flexDirection: 'row', alignItems: 'center', gap: 10 },
    selectorText: { fontSize: 14, color: '#9CA3AF', fontWeight: 'bold' },
    selectorTextSelected: { color: '#111827' },

    /* Visual abas (tabs) */
    tabContainer: { flexDirection: 'row', gap: 10, marginVertical: 5 },
    tab: { flex: 1, flexDirection: 'row', alignItems: 'center', justifyContent: 'center', gap: 8, paddingVertical: 14, borderRadius: 15, borderWidth: 1.5, borderColor: '#10B981', backgroundColor: '#FFF' },
    tabActive: { backgroundColor: '#10B981' },
    tabText: { fontSize: 10, fontWeight: '900', color: '#10B981', letterSpacing: 0.5 },
    tabTextActive: { color: '#FFF' },

    /* Dynamic recipe rows styling */
    recipeHeaderRow: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', marginTop: 15, marginBottom: 5 },
    addRowBtn: { flexDirection: 'row', alignItems: 'center', gap: 5 },
    addRowText: { fontSize: 11, fontWeight: '900', color: '#10B981' },
    rowCard: { padding: 18, borderRadius: 20, gap: 12 },
    rowTop: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' },
    rowNumber: { fontSize: 11, fontWeight: '900', color: '#10B981', letterSpacing: 0.5 },
    rowFields: { flexDirection: 'row', gap: 10 },
    inputField: { backgroundColor: '#F3F4F6', borderRadius: 12, paddingVertical: 12, paddingHorizontal: 15, fontSize: 14, fontWeight: '700', color: '#111827', borderWidth: 1.5, borderColor: '#E5E7EB' },
    unitSelector: { flex: 3, flexDirection: 'row', gap: 4, alignItems: 'center' },
    unitBtn: { flex: 1, paddingVertical: 10, borderRadius: 10, backgroundColor: '#E5E7EB', alignItems: 'center', justifyContent: 'center' },
    unitBtnActive: { backgroundColor: '#10B981' },
    unitBtnText: { fontSize: 9, fontWeight: '900', color: '#4B5563' },
    unitBtnTextActive: { color: '#FFF' },

    suggestionsContainer: { flexDirection: 'row', marginTop: 8, paddingBottom: 5 },
    suggestionChip: { backgroundColor: '#D1FAE5', paddingHorizontal: 12, paddingVertical: 6, borderRadius: 15, marginRight: 8, borderWidth: 1, borderColor: '#34D399' },
    suggestionText: { color: '#065F46', fontSize: 11, fontWeight: '700' },

    /* Notes field */
    notesInput: { backgroundColor: '#FFF', borderRadius: 15, padding: 18, fontSize: 14, fontWeight: '600', color: '#111827', borderWidth: 1.5, borderColor: '#E5E7EB', minHeight: 100, textAlignVertical: 'top' },

    /* Modal dialogs */
    modalOverlay: { ...StyleSheet.absoluteFillObject, backgroundColor: 'rgba(0,0,0,0.5)', justifyContent: 'center', padding: 25, zIndex: 10 },
    modalCard: { maxHeight: '75%', padding: 20, borderRadius: 25 },
    modalHeader: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', borderBottomWidth: 1, borderColor: '#E5E7EB', paddingBottom: 15, marginBottom: 15 },
    modalTitle: { fontSize: 16, fontWeight: '900', color: '#111827' },
    modalList: { flex: 1 },
    modalEmptyText: { color: '#9CA3AF', fontSize: 13, textAlign: 'center', marginVertical: 20, fontWeight: '600' },
    modalItem: { flexDirection: 'row', alignItems: 'center', gap: 10, paddingVertical: 15, borderBottomWidth: 1, borderColor: '#F3F4F6' },
    modalItemText: { fontSize: 14, color: '#374151', fontWeight: 'bold' }
});

import React, { useState, useEffect } from 'react';
import { View, Text, StyleSheet, FlatList, TouchableOpacity, Modal, TextInput, Alert, ActivityIndicator, Dimensions, ScrollView } from 'react-native';
import { v4 as uuidv4 } from 'uuid';
import { 
    getAllPlantings, insertPlanting, updatePlanting, deletePlanting, 
    getFields, insertField, getDashboardCropStats 
} from '../database/database';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons, MaterialCommunityIcons } from '@expo/vector-icons';
import { useTheme } from '../theme/ThemeContext';

import AgroButton from '../components/common/AgroButton';
import AgroInput from '../components/common/AgroInput';
import AgroOptionsModal from '../components/common/AgroOptionsModal';
import AgroStateOverlay from '../components/common/AgroStateOverlay';

const { width } = Dimensions.get('window');

const STATUS_OPCOES = ['SEMENTE', 'DESENVOLVIMENTO', 'PRODUÇÃO', 'FINALIZADO'];
const FILTROS = ['TODAS', ...STATUS_OPCOES];

export default function CulturasScreen({ navigation }) {
    const { theme } = useTheme();
    const [plantings, setPlantings] = useState([]);
    const [fields, setFields] = useState([]);
    const [stats, setStats] = useState({ totalCulturas: 0, areaTotal: 0, emProducao: 0 });
    
    const [loading, setLoading] = useState(true);
    const [filterStatus, setFilterStatus] = useState('TODAS');
    const [searchText, setSearchText] = useState('');
    
    const [modalVisible, setModalVisible] = useState(false);
    const [talhaoModalVisible, setTalhaoModalVisible] = useState(false);
    
    const [editingItem, setEditingItem] = useState(null);
    const [selectedItemActions, setSelectedItemActions] = useState(null);

    // Formulário de Plantio (Cultura)
    const [fieldUuid, setFieldUuid] = useState('');
    const [cropName, setCropName] = useState('');
    const [varietyName, setVarietyName] = useState('');
    const [plantingDate, setPlantingDate] = useState('');
    const [expectedYield, setExpectedYield] = useState('');
    const [status, setStatus] = useState('SEMENTE');

    // Formulário de Talhão
    const [talhaoNome, setTalhaoNome] = useState('');
    const [talhaoArea, setTalhaoArea] = useState('');

    useEffect(() => { loadData(); }, []);

    const loadData = async () => {
        setLoading(true);
        try { 
            const dataPlantings = await getAllPlantings(); 
            const dataFields = await getFields();
            const dataStats = await getDashboardCropStats();
            
            setPlantings(dataPlantings);
            setFields(dataFields);
            setStats(dataStats);
        } catch (e) { 
            console.error(e);
        } finally { 
            setLoading(false); 
        }
    };

    const resetForm = () => {
        setEditingItem(null);
        setFieldUuid(fields.length > 0 ? fields[0].uuid : '');
        setCropName('');
        setVarietyName('');
        // Format YYYY-MM-DD
        setPlantingDate(new Date().toISOString().split('T')[0]);
        setExpectedYield('');
        setStatus('SEMENTE');
    };

    const handleEdit = (item) => {
        setEditingItem(item);
        setFieldUuid(item.field_uuid);
        setCropName(item.crop_name);
        setVarietyName(item.variety_name || '');
        setPlantingDate(item.planting_date);
        setExpectedYield(item.expected_yield ? item.expected_yield.toString() : '');
        setStatus(item.status || 'SEMENTE');
        setSelectedItemActions(null);
        setModalVisible(true);
    };

    const handleSavePlanting = async () => {
        if (!fieldUuid || !cropName.trim() || !plantingDate.trim()) {
            return Alert.alert('Atenção', 'Talhão, Cultura e Data são obrigatórios.');
        }

        try {
            const payload = {
                uuid: editingItem ? editingItem.uuid : uuidv4(),
                field_uuid: fieldUuid,
                crop_name: cropName.toUpperCase(),
                variety_name: varietyName.toUpperCase(),
                planting_date: plantingDate,
                expected_yield: parseFloat(expectedYield) || 0,
                status: status
            };

            if (editingItem) {
                await updatePlanting(payload);
                Alert.alert('Sucesso', 'Cultura atualizada com sucesso!');
            } else {
                await insertPlanting(payload);
                Alert.alert('Sucesso', 'Cultura cadastrada com sucesso!');
            }

            setModalVisible(false); 
            loadData();
        } catch (e) { 
            Alert.alert('Erro', 'Não foi possível salvar a cultura.'); 
        }
    };

    const handleSaveTalhao = async () => {
        if (!talhaoNome.trim()) return Alert.alert('Atenção', 'O nome do talhão é obrigatório.');
        try {
            await insertField({
                uuid: uuidv4(),
                nome: talhaoNome.toUpperCase(),
                area: parseFloat(talhaoArea) || 0
            });
            Alert.alert('Sucesso', 'Talhão criado!');
            setTalhaoModalVisible(false);
            setTalhaoNome('');
            setTalhaoArea('');
            loadData();
        } catch (e) {
            Alert.alert('Erro', 'Não foi possível criar o talhão.');
        }
    };

    const handleDelete = (item) => {
        Alert.alert('Excluir Cultura', `Deseja realmente remover ${item.crop_name} do sistema?`, [
            { text: 'Cancelar', style: 'cancel' }, 
            { 
                text: 'Sim, Excluir', 
                style: 'destructive', 
                onPress: async () => { 
                    await deletePlanting(item.uuid); 
                    setSelectedItemActions(null);
                    loadData(); 
                } 
            }
        ]);
    };

    const getStatusColor = (st) => {
        switch(st) {
            case 'SEMENTE': return '#F59E0B'; // Amarelo
            case 'DESENVOLVIMENTO': return '#3B82F6'; // Azul
            case 'PRODUÇÃO': return '#10B981'; // Verde
            case 'FINALIZADO': return '#6B7280'; // Cinza
            default: return '#14B8A6';
        }
    };

    const filteredPlantings = plantings.filter(p => {
        const matchStatus = filterStatus === 'TODAS' || p.status === filterStatus;
        const matchText = p.crop_name.includes(searchText.toUpperCase()) || (p.variety_name && p.variety_name.includes(searchText.toUpperCase()));
        return matchStatus && matchText;
    });

    return (
        <View style={[styles.container, { backgroundColor: theme?.colors?.bg || '#0B121E' }]}>
            
            {/* CABEÇALHO COM INDICADORES (GLASSMORPHISM) */}
            <LinearGradient colors={['#1F2937', '#111827']} style={styles.header}>
                <View style={styles.headerTop}>
                    <TouchableOpacity onPress={() => navigation.goBack()} style={styles.backBtn}>
                        <Ionicons name="arrow-back" size={24} color="#FFF" />
                    </TouchableOpacity>
                    <Text style={styles.headerTitle}>GESTÃO DE CULTURAS</Text>
                    <View style={{ width: 40 }} />
                </View>

                {/* KPIs */}
                <View style={styles.kpiContainer}>
                    <View style={styles.kpiCard}>
                        <Text style={styles.kpiValue}>{stats.totalCulturas}</Text>
                        <Text style={styles.kpiLabel}>CULTURAS</Text>
                    </View>
                    <View style={styles.kpiCard}>
                        <Text style={styles.kpiValue}>{stats.areaTotal.toFixed(1)}</Text>
                        <Text style={styles.kpiLabel}>ÁREA (HA)</Text>
                    </View>
                    <View style={styles.kpiCard}>
                        <Text style={[styles.kpiValue, { color: '#10B981' }]}>{stats.emProducao}</Text>
                        <Text style={styles.kpiLabel}>PRODUÇÃO</Text>
                    </View>
                </View>

                {/* BUSCA */}
                <View style={styles.searchBox}>
                    <Ionicons name="search" size={20} color="#6B7280" style={{marginRight: 10}} />
                    <TextInput 
                        style={styles.searchInput}
                        placeholder="Buscar por Cultura ou Variedade..."
                        placeholderTextColor="#6B7280"
                        value={searchText}
                        onChangeText={setSearchText}
                    />
                </View>
            </LinearGradient>

            {/* FILTROS PILLS */}
            <View style={styles.filtersContainer}>
                <ScrollView horizontal showsHorizontalScrollIndicator={false} contentContainerStyle={{ paddingHorizontal: 20 }}>
                    {FILTROS.map(f => (
                        <TouchableOpacity 
                            key={f} 
                            style={[styles.pill, filterStatus === f && { backgroundColor: getStatusColor(f), borderColor: getStatusColor(f) }]}
                            onPress={() => setFilterStatus(f)}
                        >
                            <Text style={[styles.pillText, filterStatus === f && { color: '#FFF' }]}>{f}</Text>
                        </TouchableOpacity>
                    ))}
                </ScrollView>
            </View>

            {loading ? (
                <View style={styles.center}><ActivityIndicator size="large" color="#10B981" /></View>
            ) : (
                <FlatList
                    data={filteredPlantings}
                    keyExtractor={item => item.uuid}
                    initialNumToRender={8}
                    maxToRenderPerBatch={10}
                    windowSize={5}
                    removeClippedSubviews={true}
                    showsVerticalScrollIndicator={false}
                    contentContainerStyle={plantings.length === 0 ? {flex: 1} : { paddingBottom: 100 }}
                    renderItem={({ item }) => (
                        <TouchableOpacity 
                            activeOpacity={0.8}
                            onPress={() => handleEdit(item)}
                            onLongPress={() => setSelectedItemActions(item)}
                            style={styles.cardContainer}
                        >
                            <LinearGradient colors={['#1F2937', '#111827']} style={styles.cardGradient}>
                                <View style={styles.cardHeader}>
                                    <View style={styles.cardTitleRow}>
                                        <MaterialCommunityIcons name="leaf" size={20} color={getStatusColor(item.status)} />
                                        <Text style={styles.cardTitle}>{item.crop_name}</Text>
                                    </View>
                                    <View style={[styles.statusTag, { backgroundColor: getStatusColor(item.status) + '20', borderColor: getStatusColor(item.status) }]}>
                                        <Text style={[styles.statusText, { color: getStatusColor(item.status) }]}>{item.status}</Text>
                                    </View>
                                </View>
                                
                                <View style={styles.cardBody}>
                                    <View style={styles.infoCol}>
                                        <Text style={styles.infoLabel}>TALHÃO / ÁREA</Text>
                                        <Text style={styles.infoValue}>{item.field_nome} ({item.field_area || 0} ha)</Text>
                                    </View>
                                    <View style={styles.infoCol}>
                                        <Text style={styles.infoLabel}>VARIEDADE</Text>
                                        <Text style={styles.infoValue}>{item.variety_name || '--'}</Text>
                                    </View>
                                </View>
                                
                                <View style={styles.cardFooter}>
                                    <Ionicons name="calendar-outline" size={14} color="#9CA3AF" />
                                    <Text style={styles.footerText}>Plantio: {item.planting_date}</Text>
                                    <View style={{flex: 1}} />
                                    <Text style={styles.footerYield}>Yield Est: {item.expected_yield} kg</Text>
                                </View>
                            </LinearGradient>
                        </TouchableOpacity>
                    )}
                ListEmptyComponent={
                    <AgroStateOverlay 
                        state="empty" 
                        message="Você ainda não cadastrou nenhuma cultura. Cadastre sua primeira safra ou cultura para iniciar o ciclo de manejo e acompanhamento."
                        icon="leaf-outline"
                        onRetry={() => { resetForm(); setModalVisible(true); }}
                    />
                }
            />
            )}

            <TouchableOpacity style={styles.fab} onPress={() => { resetForm(); setModalVisible(true); }}>
                <LinearGradient colors={['#10B981', '#059669']} style={styles.fabGradient}>
                    <Ionicons name="add" size={32} color="#FFF" />
                </LinearGradient>
            </TouchableOpacity>

            {/* MODAL DE CADASTRO DE CULTURA */}
            <Modal visible={modalVisible} transparent animationType="slide">
                <View style={styles.overlay}>
                    <View style={styles.modalContent}>
                        <View style={styles.modalHeader}>
