    actionBtn: {
        backgroundColor: '#10B981',
        borderRadius: 14,
        paddingVertical: 18,
        alignItems: 'center',
        elevation: 4
    },
    actionBtnText: { color: '#FFF', fontWeight: '900', fontSize: 14, letterSpacing: 1 },
    resultBox: {
        flexDirection: 'row',
