                >
                    <LinearGradient colors={['#991B1B', '#7F1D1D']} style={styles.logoutGradient}>
                        <Text style={styles.logoutBtnText}>Sair da Conta</Text>
                    </LinearGradient>
                </TouchableOpacity>

                <View style={styles.versionInfo}>
