import React, { useState, useEffect } from 'react';
import { StyleSheet, View, 
    Text, 
    FlatList, 
    TouchableOpacity, 
    Modal, 
    Alert } from 'react-native';
import { Ionicons } from '@expo/vector-icons';
import { LinearGradient } from 'expo-linear-gradient';
import { useTheme } from '../theme/ThemeContext';
import { executeQuery } from '../database/database';
import { v4 as uuidv4 } from 'uuid';
import Card from '../components/common/Card';
import AgroButton from '../components/common/AgroButton';
import AgroInput from '../components/common/AgroInput';
import AgroOptionsModal from '../components/common/AgroOptionsModal';
import AgroStateOverlay from '../components/common/AgroStateOverlay';

const SCREEN_VERSION = 'v2.0.0';

export default function TalhoesScreen({ navigation }) {
    const { theme } = useTheme();
    const [talhoes, setTalhoes] = useState([]);
    const [modalVisible, setModalVisible] = useState(false);
    const [editItem, setEditItem] = useState(null);
    const [form, setForm] = useState({ nome: '', area_ha: '', observacao: '' });
    const [selectedItemActions, setSelectedItemActions] = useState(null);

    const handleEdit = (item) => {
        setEditItem(item);
        setForm({ ...item, area_ha: String(item.area_ha) });
        setModalVisible(true);
    };

    useEffect(() => {
        loadTalhoes();
    }, []);

    const loadTalhoes = async () => {
        try {
            const res = await executeQuery('SELECT * FROM talhoes WHERE is_deleted = 0 ORDER BY nome ASC');
            const rows = [];
            for (let i = 0; i < res.rows.length; i++) rows.push(res.rows.item(i));
            setTalhoes(rows);
        } catch (e) {
            console.error(e);
        }
    };

    const handleSave = async () => {
        if (!form.nome) return Alert.alert('Aviso', 'Nome é obrigatório');
        try {
            if (editItem) {
                await executeQuery(
                    'UPDATE talhoes SET nome = ?, area_ha = ?, observacao = ?, last_updated = ? WHERE uuid = ?',
                    [(form.nome || '').toUpperCase(), parseFloat(form.area_ha) || 0, (form.observacao || '').toUpperCase(), new Date().toISOString(), editItem.uuid]
                );
            } else {
                await executeQuery(
                    'INSERT INTO talhoes (uuid, nome, area_ha, observacao, last_updated) VALUES (?, ?, ?, ?, ?)',
                    [uuidv4(), (form.nome || '').toUpperCase(), parseFloat(form.area_ha) || 0, (form.observacao || '').toUpperCase(), new Date().toISOString()]
                );
            }
            setModalVisible(false);
            setEditItem(null);
            setForm({ nome: '', area_ha: '', observacao: '' });
            loadTalhoes();
        } catch (e) {
            Alert.alert('Erro', 'Falha ao salvar talhão');
        }
    };

    const handleDelete = (item) => {
        Alert.alert('Excluir', `Deseja excluir o talhão ${item.nome}?`, [
            { text: 'Cancelar', style: 'cancel' },
            { 
                text: 'EXCLUIR', 
                style: 'destructive',
                onPress: async () => {
                    await executeQuery('UPDATE talhoes SET is_deleted = 1 WHERE uuid = ?', [item.uuid]);
                    loadTalhoes();
                }
            }
        ]);
    };

    const renderItem = ({ item }) => (
        <Card 
            style={styles.itemCard}
            onPress={() => handleEdit(item)}
            onLongPress={() => setSelectedItemActions(item)}
        >
            <View style={styles.itemHeader}>
                <View style={[styles.iconContainer, { backgroundColor: theme?.colors?.surface || 'rgba(255,255,255,0.05)' }]}>
                    <Ionicons name="leaf" size={20} color={theme?.colors?.primary || '#10B981'} />
                </View>
                <View style={{ flex: 1 }}>
                    <Text style={[styles.itemName, { color: theme?.colors?.textMain || '#F8FAFC' }]}>{item.nome}</Text>
                    <Text style={[styles.itemSub, { color: theme?.colors?.textSub || '#94A3B8' }]}>{item.area_ha} hectares</Text>
                </View>
                <Ionicons name="chevron-forward" size={20} color={theme?.colors?.textSub || '#9CA3AF'} />
            </View>
        </Card>
    );

    return (
        <View style={[styles.container, { backgroundColor: theme?.colors?.bg || '#F3F4F6' }]}>
            <LinearGradient colors={['#059669', '#10B981']} style={styles.header}>
                <View style={styles.headerTop}>
                    <TouchableOpacity onPress={() => navigation.goBack()}>
                        <Ionicons name="arrow-back" size={24} color="#FFF" />
                    </TouchableOpacity>
                    <Text style={styles.headerTitle}>GESTÃO DE TALHÕES</Text>
                    <TouchableOpacity onPress={() => { setEditItem(null); setForm({ nome: '', area_ha: '', observacao: '' }); setModalVisible(true); }}>
                        <Ionicons name="add-circle" size={32} color="#FFF" />
                    </TouchableOpacity>
                </View>
            </LinearGradient>

            <FlatList
                data={talhoes}
                renderItem={renderItem}
                keyExtractor={item => item.uuid}
                    initialNumToRender={8}
                    maxToRenderPerBatch={10}
                    windowSize={5}
                    removeClippedSubviews={true}
                contentContainerStyle={talhoes.length === 0 ? {flex: 1} : styles.list}
                ListEmptyComponent={
                    <AgroStateOverlay 
                        state="empty" 
                        message="Você ainda não tem nenhum talhão cadastrado. Adicione um novo talhão para começar a monitorar a fazenda."
                        icon="leaf-outline"
                        onRetry={() => { setEditItem(null); setForm({ nome: '', area_ha: '', observacao: '' }); setModalVisible(true); }}
                    />
                }

            />

            <TouchableOpacity style={[styles.fab, { backgroundColor: theme?.colors?.primary || '#10B981' }]} onPress={() => { setEditItem(null); setForm({ nome: '', area_ha: '', observacao: '' }); setModalVisible(true); }}>
                <Ionicons name="add" size={32} color="#FFF" />
            </TouchableOpacity>

            <Modal visible={modalVisible} animationType="slide" transparent>
                <View style={styles.overlay}>
                    <View style={[styles.modal, { backgroundColor: theme?.colors?.cardBg || '#1E293B' }]}>
                        <Text style={[styles.modalTitle, { color: theme?.colors?.textMain || '#F8FAFC' }]}>{editItem ? 'EDITAR TALHÃO' : 'NOVO TALHÃO'}</Text>
                        <AgroInput label="NOME DO TALHÃO" value={form.nome} onChangeText={t => setForm({...form, nome: t})} />
                        <AgroInput label="ÁREA (HA)" value={form.area_ha} keyboardType="numeric" onChangeText={t => setForm({...form, area_ha: t})} />
                        <AgroInput label="OBSERVAÇÕES" value={form.observacao} multiline numberOfLines={3} onChangeText={t => setForm({...form, observacao: t})} />
                        
                        <View style={styles.modalButtons}>
                            <AgroButton title="CANCELAR" variant="secondary" onPress={() => setModalVisible(false)} style={{ flex: 1, marginRight: 10 }} />
                            <AgroButton title="SALVAR" onPress={handleSave} style={{ flex: 1 }} />
                        </View>
                    </View>
                </View>
            </Modal>

            {/* OPTIONS MODAL DE TOQUE LONGO */}
            <AgroOptionsModal
                visible={!!selectedItemActions}
                onClose={() => setSelectedItemActions(null)}
                title={selectedItemActions?.nome || ''}
                subtitle={`${selectedItemActions?.area_ha || 0} ha`}
                onEdit={() => handleEdit(selectedItemActions)}
                onDelete={() => handleDelete(selectedItemActions)}
                editLabel="Editar Talhão"
                deleteLabel="Excluir Talhão"
            />
        </View>
    );
}

