export default function LoginScreen({ navigation, onLoginSuccess }) {
    const [usuario, setUsuario] = useState('');
    const [senha, setSenha] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [loading, setLoading] = useState(false);
    const [logoTaps, setLogoTaps] = useState(0); // NOVO: Easter Egg ADM
    const fadeAnim = useRef(new Animated.Value(0)).current;

    useEffect(() => {
        Animated.timing(fadeAnim, { toValue: 1, duration: 1000, useNativeDriver: true }).start();
    }, []);

    const handleLogin = async () => {
        const u = usuario.trim();
        const p = senha.trim();
        if (!u || !p) return Alert.alert('Campos Vazios', 'Por favor, informe suas credenciais.');
        setLoading(true);
        try {
            const res = await AuthService.loginWithEmail(u, p);
            if (res.success) {
                const sessionObj = res.session || res.user;
                if (onLoginSuccess) {
                    onLoginSuccess(res.user);
                } else {
                    // Roteamento baseado na Role
                    const role = sessionObj?.role;
                    if (role === 'CLIENTE') {
                        navigation.replace('ClientTabs');
                    } else if (role === 'ADMIN') {
                        navigation.replace('AdminSelector');
                    } else {
                        navigation.replace('Home'); // Painel do Agrônomo
                    }
                }
            } else {
                 Alert.alert('Erro', res.message || 'Credenciais inválidas.');
            }
        } catch (e) {
            Alert.alert('Erro', 'Falha na conexão com o servidor.');
        } finally {
            setLoading(false);
        }
    };

    // NOVO: Lógica do Backdoor do ADM
    const handleLogoTap = () => {
        const newTaps = logoTaps + 1;
        setLogoTaps(newTaps);
        if (newTaps >= 7) {
            setLogoTaps(0);
            navigation.replace('AdminSelector');
        }
    };

    return (
        <View style={styles.container}>
            <LinearGradient
                colors={['#0F3D2E', '#1B5E20', 'transparent']}
