                            </TouchableOpacity>

                            <View style={styles.bioArea}>
                                <Text style={styles.bioTxt}>Acesso Biométrico</Text>
                                <TouchableOpacity style={styles.bioCircle} onPress={async () => {
                                    setLoading(true);
                                    const res = await AuthService.loginWithBiometrics();
                                    if (res.success) {
                                        if (onLoginSuccess) {
                                            onLoginSuccess(res.user);
                                        } else {
                                            if (res.user.role === 'CLIENTE') navigation.replace('ClientTabs');
                                            else if (res.user.role === 'ADMIN') navigation.replace('AdminSelector');
                                            else navigation.replace('Home');
                                        }
                                    } else {
                                        Alert.alert('Biometria', res.message);
                                    }
                                    setLoading(false);
                                }}>
                                    <MaterialCommunityIcons name="fingerprint" size={35} color="#1B5E20" />
                                </TouchableOpacity>
                            </View>

                            <View style={styles.footerLinks}>
