import { executeQuery, genericUpsert } from '../database/database';
import { getSupabase, syncTable } from './supabase';

export const AgronomistService = {
    /**
     * Recupera o código de convite de um agrônomo (local ou remoto)
     */
    getAgronomistCode: async (agronomistUuid) => {
        try {
            // 1. Tenta local primeiro
            const res = await executeQuery('SELECT code FROM agronomist_codes WHERE agronomist_id = ?', [agronomistUuid]);
            if (res.rows.length > 0) {
                return res.rows.item(0).code;
            }

            // 2. Tenta remoto
            const supabase = getSupabase();
            const { data, error } = await supabase
                .from('agronomist_codes')
                .select('code')
                .eq('agronomist_id', agronomistUuid)
                .single();

            if (data && data.code) {
                // Salva localmente
                await genericUpsert('agronomist_codes', {
                    agronomist_id: agronomistUuid,
                    code: data.code,
                    created_at: new Date().toISOString()
                });
                return data.code;
            }
            return null;
        } catch (e) {
            console.log('Erro ao obter código do agrônomo:', e.message || e);
            return null;
        }
    },

    /**
     * Vincula o cliente logado a um agrônomo a partir do código deste
     */
    linkWithAgronomist: async (clientUuid, code) => {
        try {
            const cleanCode = code.trim().toUpperCase();
            if (cleanCode.length !== 9) { // AGRO-XXXX
                throw new Error('Código de convite inválido. Deve ser no formato AGRO-XXXX.');
            }

            const supabase = getSupabase();

            // 1. Verifica se o código existe remotamente
            const { data: codeData, error: codeError } = await supabase
                .from('agronomist_codes')
                .select('agronomist_id')
                .eq('code', cleanCode)
                .single();

            if (codeError || !codeData) {
                throw new Error('Código de convite não encontrado ou inválido.');
            }

            const agronomistUuid = codeData.agronomist_id;

            if (agronomistUuid === clientUuid) {
                throw new Error('Você não pode se vincular a si mesmo!');
            }

            // 2. Cria o vínculo localmente
            const linkUuid = `${clientUuid}_${agronomistUuid}`; // UUID composto determinístico
            const newLink = {
                uuid: linkUuid,
                agronomist_id: agronomistUuid,
                client_id: clientUuid,
                status: 'ACTIVE',
                source_platform: 'mobile',
                sync_status: 0,
                last_updated: new Date().toISOString()
            };

            await genericUpsert('agronomist_client_links', newLink);

            // 3. Tenta sincronizar imediatamente para a nuvem
            try {
                await syncTable('agronomist_client_links');
            } catch (syncErr) {
                console.log('⚠️ Sincronismo em background agendado:', syncErr.message);
            }

            return { success: true, agronomistId: agronomistUuid };
        } catch (e) {
            console.log('Erro ao criar vínculo:', e.message || e);
            return { success: false, error: e.message };
        }
    },

    /**
     * Recupera os vínculos ativos (Agrônomo vê seus Clientes, Cliente vê seu Agrônomo)
     */
    getActiveLinks: async (userUuid, role) => {
        try {
            let sql = '';
            let params = [];

            if (role === 'AGRONOMO') {
                // Agrônomo quer ver a lista de clientes vinculados a ele
                sql = `
                    SELECT l.*, u.nome_completo as client_name, u.email as client_email, u.telefone as client_phone
                    FROM agronomist_client_links l
                    JOIN usuarios u ON l.client_id = u.uuid
                    WHERE l.agronomist_id = ? AND l.status = 'ACTIVE' AND l.is_deleted = 0
                `;
                params = [userUuid];
            } else {
                // Cliente quer ver o agrônomo vinculado a ele
                sql = `
                    SELECT l.*, u.nome_completo as agronomist_name, u.email as agronomist_email, u.telefone as agronomist_phone
                    FROM agronomist_client_links l
                    JOIN usuarios u ON l.agronomist_id = u.uuid
                    WHERE l.client_id = ? AND l.status = 'ACTIVE' AND l.is_deleted = 0
                `;
                params = [userUuid];
            }

            const res = await executeQuery(sql, params);
            const rows = [];
            for (let i = 0; i < res.rows.length; i++) {
                rows.push(res.rows.item(i));
            }
            return rows;
        } catch (e) {
            console.log('Erro ao obter vínculos:', e.message || e);
            return [];
        }
    }
};

/**
 * DashboardService
 * Centraliza a lógica de busca de dados para o Dashboard Executivo do banco de dados local.
 */
import { executeQuery } from '../database/database';

export const DashboardService = {
    /**
     * Busca dados consolidados do dashboard do banco de dados local
     */
    getDashboardData: async (propertyId = 'all', period = 'month') => {
        try {
            const date = new Date();
            let startDate;

            if (period === 'month') {
                date.setDate(date.getDate() - 30);
                startDate = date.toISOString().split('T')[0];
            } else if (period === 'year') {
                date.setFullYear(date.getFullYear() - 1);
                startDate = date.toISOString().split('T')[0];
            } else if (period === 'safra') {
                // Safra padrão: últimos 6 meses (exemplo)
                date.setMonth(date.getMonth() - 6);
                startDate = date.toISOString().split('T')[0];
            } else {
                // All time (fallback)
                startDate = '1970-01-01';
            }
            
            // 1. FINANCEIRO (Receitas de Vendas)
            const resVendas = await executeQuery(
                `SELECT SUM(valor * quantidade) as total FROM vendas WHERE data >= ? AND is_deleted = 0`, 
                [startDate]
            );
            const revenue = resVendas.rows.item(0).total || 0;

            // 2. FINANCEIRO (Despesas de Compras e Custos)
            const resCompras = await executeQuery(
                `SELECT SUM(valor) as total FROM compras WHERE data >= ? AND is_deleted = 0`, 
                [startDate]
            );
            const resCustos = await executeQuery(
                `SELECT SUM(valor_total) as total FROM custos WHERE data >= ? AND is_deleted = 0`, 
                [startDate]
            );
            const expenses = (resCompras.rows.item(0).total || 0) + (resCustos.rows.item(0).total || 0);
            
            const netResult = revenue - expenses;

            // 3. COLHEITA (Produção)
            const resColheita = await executeQuery(
                `SELECT SUM(quantidade) as total FROM colheitas WHERE data >= ? AND is_deleted = 0`, 
                [startDate]
            );
            const producaoTotal = resColheita.rows.item(0).total || 0;

            // 4. ATIVIDADES RECENTES (Unificado)
            const activities = [];
            
            // Vendas Recentes
            const resRecVendas = await executeQuery(
                `SELECT * FROM vendas WHERE is_deleted = 0 ORDER BY data DESC, id DESC LIMIT 2`
            );
            for(let i=0; i<resRecVendas.rows.length; i++) {
                const item = resRecVendas.rows.item(i);
                activities.push({
                    id: `v-${item.uuid}`,
                    type: 'finance',
                    title: 'Venda: ' + item.produto,
                    description: item.cliente,
                    value: `+ R$ ${(item.valor * item.quantidade).toFixed(2)}`,
                    time: item.data,
                    icon: 'cash-outline'
                });
            }

            // Colheitas Recentes
            const resRecColheitas = await executeQuery(
                `SELECT * FROM colheitas WHERE is_deleted = 0 ORDER BY data DESC, id DESC LIMIT 1`
            );
            for(let i=0; i<resRecColheitas.rows.length; i++) {
                const item = resRecColheitas.rows.item(i);
                activities.push({
                    id: `c-${item.uuid}`,
                    type: 'field',
                    title: 'Colheita: ' + item.cultura,
                    description: item.produto,
                    value: `${item.quantidade} kg`,
                    time: item.data,
                    icon: 'leaf-outline'
                });
            }

            // 5. ALERTAS INTELIGENTES
            const alerts = [];
            
            // Alerta: Estoque Baixo
            const resEstoque = await executeQuery('SELECT * FROM estoque WHERE quantidade < 10');
            if (resEstoque.rows.length > 0) {
                alerts.push({
                    id: 'a-stock',
                    type: 'warning',
                    title: 'Estoque Baixo',
                    message: `Existem ${resEstoque.rows.length} itens com nível crítico.`,
                    screen: 'Estoque'
                });
            }

            // Alerta: Irrigação Pendente (Exemplo: se não houve irrigação hoje)
            const today = new Date().toISOString().split('T')[0];
            // Nota: Se a tabela irrigacao não existir, isso vai dar erro, mas o try/catch segura.
            try {
                const resIrrig = await executeQuery('SELECT COUNT(*) as c FROM irrigacao WHERE data = ?', [today]);
                if (resIrrig.rows.item(0).c === 0) {
                    alerts.push({
                        id: 'a-irrig',
                        type: 'info',
                        title: 'Irrigação Diária',
                        message: 'Nenhum turno de irrigação registrado hoje.',
                        screen: 'Irrigacao'
                    });
                }
            } catch (e) {
                // Tabela irrigação pode não existir ainda no esquema
            }

            if (alerts.length === 0) {
                alerts.push({ id: 'a1', type: 'success', title: 'Operação Normal', message: 'Tudo em ordem com a sua fazenda.', screen: 'Home' });
            }

            return {
                financial: {
                    revenue,
                    expenses,
                    netResult,
                    trend: 0,
                    trendType: netResult >= 0 ? 'up' : 'down'
                },
                kpis: [
                    { id: '1', title: 'Produção Total', value: `${producaoTotal.toLocaleString()} kg`, icon: 'leaf', trend: '---', trendType: 'up', color: '#10B981' },
                    { id: '2', title: 'Receita Operacional', value: `R$ ${revenue.toLocaleString()}`, icon: 'cash', trend: '---', trendType: 'up', color: '#3B82F6' },
                    { id: '3', title: 'Despesas Gerais', value: `R$ ${expenses.toLocaleString()}`, icon: 'cart', trend: '---', trendType: 'down', color: '#EF4444' },
                    { id: '4', title: 'Margem Líquida', value: revenue > 0 ? `${((netResult / revenue) * 100).toFixed(1)}%` : '0%', icon: 'pie-chart', trend: '---', trendType: 'up', color: '#8B5CF6' }
                ],
                alerts: alerts,
                activities: activities.sort((a,b) => b.time.localeCompare(a.time)),
                chartData: await DashboardService.getProductionChartData()
            };
        } catch (error) {
            console.error('Erro ao buscar dados reais do dashboard:', error);
            throw error;
        }
    },

    getProductionChartData: async () => {
        try {
            const labels = [];
            const data = [];
            
            for(let i=6; i>=0; i--) {
                const d = new Date();
                d.setDate(d.getDate() - i);
                const dayStr = d.toISOString().split('T')[0];
                labels.push(dayStr.split('-')[2] + '/' + dayStr.split('-')[1]);
                
                const res = await executeQuery(`SELECT SUM(quantidade) as total FROM colheitas WHERE data = ? AND is_deleted = 0`, [dayStr]);
                data.push(res.rows.item(0).total || 0);
            }

            return {
                labels,
                datasets: [{ data }]
            };
        } catch (e) {
            return { labels: ['Erro'], datasets: [{ data: [0] }] };
        }
    }
};

import { executeQuery } from '../database/database';

/**
 * SERVIÇO DE ESTOQUE ENTERPRISE - BUILD #107
 * Responsável pela integridade física dos produtos e histórico de movimentações.
 */
class EstoqueService {

    /**
     * Atualiza a quantidade de um produto de forma segura
     */
    static async movimentar(id_produto, delta, motivo = 'AJUSTE', uuid_referencia = null) {
        const timestamp = new Date().toISOString();

        try {
            // 1. Busca o saldo atual
            const res = await executeQuery('SELECT * FROM estoque WHERE id = ? OR produto = ?', [id_produto, id_produto]);

            if (res.rows.length === 0) {
                // Se não existe, cria o registro inicial (se delta for positivo)
                if (delta < 0) return { success: false, error: 'Estoque insuficiente (não existente)' };

                await executeQuery(
                    'INSERT INTO estoque (produto, quantidade, last_updated) VALUES (?, ?, ?)',
                    [id_produto, delta, timestamp]
                );
            } else {
                const item = res.rows.item(0);
                let novaQtd = (item.quantidade || 0) + delta;

                // Regra de Ouro: Nunca negativo
                if (novaQtd < 0) {
                    console.warn(`[Estoque] Saldo insuficiente para ${id_produto}. Ajustado para 0.`);
                    novaQtd = 0;
                }

                await executeQuery(
                    'UPDATE estoque SET quantidade = ?, last_updated = ? WHERE id = ?',
                    [novaQtd, timestamp, item.id]
                );
            }

            // 2. Registra na tabela de movimentação histórica
            const { v4: uuidv4 } = require('uuid');
            await executeQuery(
                `INSERT INTO movimentacao_estoque (
                    uuid, produto_uuid, tipo, quantidade, motivo, data, last_updated, sync_status
                ) VALUES (?, ?, ?, ?, ?, ?, ?, 0)`,
                [
                    uuidv4(),
                    id_produto,
                    delta > 0 ? 'ENTRADA' : 'SAIDA',
                    Math.abs(delta),
                    motivo,
                    timestamp,
                    timestamp
                ]
            );

            return { success: true };
        } catch (error) {
            console.error('❌ [EstoqueService Error]:', error);
            throw error;
        }
    }

    /**
     * Busca o saldo consolidado de um produto
     */
    static async getSaldo(id_produto) {
        const res = await executeQuery('SELECT quantidade FROM estoque WHERE id = ? OR produto = ?', [id_produto, id_produto]);
        return res.rows.length > 0 ? res.rows.item(0).quantidade : 0;
    }

    /**
     * Retorna a lista completa de estoque para o Dashboard (Com Unidade do Cadastro)
     */
    static async getListaConsolidada() {
        const res = await executeQuery(`
            SELECT e.*, c.unidade, c.tipo as categoria 
            FROM estoque e
            LEFT JOIN cadastro c ON UPPER(e.produto) = UPPER(c.nome)
            ORDER BY e.produto ASC
        `);
        const rows = [];
        for (let i = 0; i < res.rows.length; i++) rows.push(res.rows.item(i));
        return rows;
    }
}

export default EstoqueService;

import * as XLSX from 'xlsx';
import * as FileSystem from 'expo-file-system';
import * as Sharing from 'expo-sharing';
import { Alert } from 'react-native';

export const ExportService = {
    /**
     * Exporta um array de objetos para Excel e abre o menu de compartilhamento
     * @param {Array} data - Lista de objetos [{col1: val, col2: val}]
     * @param {String} fileName - Nome do arquivo (sem extensão)
     */
    exportToExcel: async (data, fileName = 'relatorio_agrogb') => {
        try {
            if (!data || data.length === 0) {
                Alert.alert('Aviso', 'Não há dados para exportar.');
                return;
            }

            // 1. Criar worksheet
            const ws = XLSX.utils.json_to_sheet(data);
            
            // 2. Criar workbook
            const wb = XLSX.utils.book_new();
            XLSX.utils.book_append_sheet(wb, ws, "Relatorio");

            // 3. Gerar binário base64
            const wbout = XLSX.write(wb, { type: 'base64', bookType: 'xlsx' });

            // 4. Salvar temporariamente no dispositivo
            const uri = FileSystem.cacheDirectory + `${fileName}_${new Date().getTime()}.xlsx`;
            await FileSystem.writeAsStringAsync(uri, wbout, {
                encoding: FileSystem.EncodingType.Base64
            });

            // 5. Compartilhar
            if (await Sharing.isAvailableAsync()) {
                await Sharing.shareAsync(uri, {
                    mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
                    dialogTitle: 'Exportar Relatório AgroGB',
                    UTI: 'com.microsoft.excel.xlsx'
                });
            } else {
                Alert.alert('Erro', 'Compartilhamento não disponível neste dispositivo.');
            }
        } catch (error) {
            console.error('Export Error:', error);
            Alert.alert('Erro', 'Falha ao gerar arquivo Excel.');
        }
    },
    
    /**
     * Exporta dados para um PDF formatado profissionalmente
     */
    exportToPDF: async (title, data, fileName = 'relatorio') => {
        try {
            const Print = require('expo-print');
            const html = `
                <html>
                <head>
                    <style>
                        body { font-family: 'Helvetica', sans-serif; padding: 20px; color: #333; }
                        h1 { color: #065F46; border-bottom: 2px solid #065F46; padding-bottom: 10px; }
                        table { width: 100%; border-collapse: collapse; margin-top: 20px; }
                        th { background-color: #F3F4F6; color: #065F46; text-align: left; padding: 12px; border-bottom: 1px solid #E5E7EB; }
                        td { padding: 12px; border-bottom: 1px solid #F3F4F6; }
                        .footer { margin-top: 50px; font-size: 10px; color: #9CA3AF; text-align: center; }
                    </style>
                </head>
                <body>
                    <h1>${title}</h1>
                    <p>Gerado em: ${new Date().toLocaleString()}</p>
                    <table>
                        <thead>
                            <tr>
                                ${Object.keys(data[0] || {}).map(k => `<th>${k.toUpperCase()}</th>`).join('')}
                            </tr>
