import { executeQuery, genericUpsert } from '../database/database';
import { syncTable } from './supabase';
import { ManejoService } from './ManejoService';
import 'react-native-get-random-values';
import { v4 as uuidv4 } from 'uuid';

export const RecommendationService = {
    /**
     * Cria uma nova recomendação técnica offline-first e sincroniza com a nuvem
     */
    createRecommendation: async (rec) => {
        try {
            const uuid = rec.uuid || uuidv4();
            const newRec = {
                uuid,
                agronomist_id: rec.agronomist_id,
                client_id: rec.client_id,
                farm_id: rec.farm_id || null,
                field_id: rec.field_id || null,
                planting_id: rec.planting_id || null,
                recipe_type: rec.recipe_type || 'GOTEJO', // GOTEJO ou FOLIAR
                recipe_data: typeof rec.recipe_data === 'string' ? rec.recipe_data : JSON.stringify(rec.recipe_data),
                notes: rec.notes || '',
                status: rec.status || 'PENDING', // PENDING, APPLIED, CANCELLED
                source_platform: 'mobile',
                sync_status: 0,
                last_updated: new Date().toISOString()
            };

            await genericUpsert('recommendations', newRec);

            // Tenta sincronizar com Supabase em background
            try {
                await syncTable('recommendations');
            } catch (syncErr) {
                console.log('⚠️ Sincronização em background agendada:', syncErr.message);
            }

            return { success: true, uuid };
        } catch (e) {
            console.log('Erro ao criar recomendação:', e.message || e);
            return { success: false, error: e.message };
        }
    },

    /**
     * Recupera a lista de recomendações ativas baseada na role do usuário
     */
    getRecommendations: async (userUuid, role) => {
        try {
            let sql = `
                SELECT r.*, 
                       u.nome_completo as agronomist_name, 
                       c.nome_completo as client_name,
                       fi.nome as field_name,
                       p.cultura as planting_culture
                FROM recommendations r
                LEFT JOIN usuarios u ON r.agronomist_id = u.uuid
                LEFT JOIN usuarios c ON r.client_id = c.uuid
                LEFT JOIN fields fi ON r.field_id = fi.uuid
                LEFT JOIN plantio p ON r.planting_id = p.uuid
                WHERE r.is_deleted = 0
            `;
            const params = [];

            if (role === 'AGRONOMO') {
                sql += ' AND r.agronomist_id = ?';
                params.push(userUuid);
            } else if (role === 'CLIENTE') {
                sql += ' AND r.client_id = ?';
                params.push(userUuid);
            }

            sql += ' ORDER BY r.last_updated DESC';

            const res = await executeQuery(sql, params);
            const rows = [];
            for (let i = 0; i < res.rows.length; i++) {
                const item = res.rows.item(i);
                // Converte recipe_data de JSON string para objeto JS
                try {
                    item.recipe_data = JSON.parse(item.recipe_data);
                } catch (parseErr) {
                    item.recipe_data = [];
                }
                rows.push(item);
            }
            return rows;
        } catch (e) {
            console.log('Erro ao obter recomendações:', e.message || e);
            return [];
        }
    },

    /**
     * Atualiza o status de execução de uma recomendação técnica (ex: CLIENTE clica em "Aplicar")
     */
    updateRecommendationStatus: async (uuid, status) => {
        try {
            const validStatus = ['PENDING', 'APPLIED', 'CANCELLED'];
            if (!validStatus.includes(status)) {
                throw new Error('Status de recomendação inválido.');
            }

            await executeQuery(
                `UPDATE recommendations SET status = ?, sync_status = 0, last_updated = ? WHERE uuid = ?`,
                [status, new Date().toISOString(), uuid]
            );

            // AUTO-EXECUÇÃO DO MANEJO
            if (status === 'APPLIED') {
                try {
                    const resRec = await executeQuery('SELECT * FROM recommendations WHERE uuid = ?', [uuid]);
                    if (resRec.rows.length > 0) {
                        const rec = resRec.rows.item(0);
                        let recipeData = [];
                        try { recipeData = typeof rec.recipe_data === 'string' ? JSON.parse(rec.recipe_data) : rec.recipe_data; } catch(e){}
                        
                        // Pegar a area_hectares do talhao
                        let areaHectares = 1;
                        if (rec.field_id) {
                            const resT = await executeQuery('SELECT area_hectares FROM talhoes WHERE uuid = ?', [rec.field_id]);
                            if (resT.rows.length > 0) {
                                areaHectares = parseFloat(resT.rows.item(0).area_hectares) || 1;
                            }
                        }

                        // Para cada item da receita, lançar o Manejo
                        for (const item of recipeData) {
                            const produtoNome = item.product || '';
                            const dose = parseFloat(item.dosage) || 0;
                            
                            let precoUnitario = 0;
                            const resCat = await executeQuery('SELECT preco_unitario FROM cadastro WHERE nome_comercial = ? AND is_deleted = 0 LIMIT 1', [produtoNome.toUpperCase()]);
                            if (resCat.rows.length > 0) {
                                precoUnitario = parseFloat(resCat.rows.item(0).preco_unitario) || 0;
                            }

                            const manejoObj = {
                                talhao_uuid: rec.field_id,
                                produto_nome: produtoNome,
                                praga_alvo: `PRESCRIÇÃO ${rec.recipe_type}`,
                                dose_ha: dose,
                                volume_calda_l: 0,
                                carencia_dias: 7, 
                                area_hectares: areaHectares,
                                preco_unitario: precoUnitario,
                                data: new Date().toISOString().split('T')[0]
                            };

                            await ManejoService.registrarManejo(manejoObj);
                        }
                    }
                } catch (execErr) {
                    console.log('Erro na auto-execução da prescrição:', execErr);
                }
            }

            // Tenta sincronizar com o Supabase imediatamente
            try {
                await syncTable('recommendations');
            } catch (syncErr) {
                console.log('⚠️ Sincronismo em background agendado:', syncErr.message);
            }

            return { success: true };
        } catch (e) {
            console.log('Erro ao atualizar recomendação:', e.message || e);
            return { success: false, error: e.message };
        }
    }
};

import { supabase } from './supabaseClient';
import { executeQuery } from '../database/database';
import NetInfo from '@react-native-community/netinfo';
import { v4 as uuidv4 } from 'uuid';

/**
 * SyncWorker V3 (Motor Titânio)
 * Processa a fila de sincronização (sync_outbox) de forma atômica e resiliente.
 */
export const SyncWorker = {
    
    isSyncing: false,

    /**
     * Executa um ciclo de sincronização
     */
    run: async () => {
        if (SyncWorker.isSyncing) return;
        
        try {
            const netState = await NetInfo.fetch();
            if (!netState.isConnected) return;

            SyncWorker.isSyncing = true;
            if (__DEV__) console.log('🔄 [SyncWorker V3] Iniciando processamento da fila de transações...');

            // 1. Pega itens pendentes na fila (PENDENTE ou FALHA)
            const res = await executeQuery(
                `SELECT * FROM sync_outbox WHERE status = 'PENDENTE' OR status = 'FALHA' ORDER BY criado_em ASC LIMIT 50`
            );

            if (res.rows.length === 0) {
                SyncWorker.isSyncing = false;
                return;
            }

            for (let i = 0; i < res.rows.length; i++) {
                const item = res.rows.item(i);
                await SyncWorker.processItem(item);
            }

            if (__DEV__) console.log('✅ [SyncWorker V3] Ciclo de sincronização concluído com sucesso.');
        } catch (error) {
            console.error('❌ [SyncWorker V3] Erro crítico no worker:', error);
        } finally {
            SyncWorker.isSyncing = false;
        }
    },

    /**
     * Processa um único item da fila
     */
    processItem: async (item) => {
        const { uuid, tabela, acao, registro_uuid, payload_json } = item;
        let data = {};
        
        try {
            if (payload_json) data = JSON.parse(payload_json);
        } catch (e) {
            console.error('❌ Erro de parse no payload:', payload_json);
        }

        try {
            // Marca como processando localmente
            await executeQuery(`UPDATE sync_outbox SET status = 'PROCESSANDO' WHERE uuid = ?`, [uuid]);

            let response;
            if (acao === 'INSERT' || acao === 'UPDATE') {
                response = await supabase.from(tabela).upsert(data, { onConflict: 'uuid' });
            } else if (acao === 'DELETE') {
                response = await supabase.from(tabela).delete().eq('uuid', registro_uuid);
            }

            if (response && response.error) throw response.error;

            // Sucesso: Remove da fila e atualiza status local na tabela de origem (opcional)
            await executeQuery(`DELETE FROM sync_outbox WHERE uuid = ?`, [uuid]);
            
            // Tentativa otimista de marcar sync_status = 1 na tabela original
            try {
                await executeQuery(`UPDATE ${tabela} SET sync_status = 1 WHERE uuid = ?`, [registro_uuid]);
            } catch (ignore) { }

        } catch (error) {
            if (__DEV__) console.error(`⚠️ [SyncWorker V3] Falha em ${tabela}:${registro_uuid}:`, error.message);
            
            // Incrementa tentativas e marca como falha para reprocessar depois
            await executeQuery(
                `UPDATE sync_outbox SET status = 'FALHA', tentativas = tentativas + 1 WHERE uuid = ?`,
                [uuid]
            );
        }
    },

    /**
     * Enfileira uma nova operação (Deve ser usado pelo database.js central)
     */
    enqueue: async (tabela, acao, registro_uuid, data) => {
        const id = uuidv4();
        const payload = data ? JSON.stringify(data) : null;
        const now = new Date().toISOString();
        
        await executeQuery(
            `INSERT INTO sync_outbox (uuid, tabela, registro_uuid, acao, payload_json, status, criado_em) VALUES (?, ?, ?, ?, ?, ?, ?)`,
            [id, tabela, registro_uuid, acao, payload, 'PENDENTE', now]
        );
        
        // Tenta rodar o worker imediatamente se houver conexão
        SyncWorker.run();
    }
};

import AsyncStorage from '@react-native-async-storage/async-storage';
import * as SecureStore from 'expo-secure-store';
import { executeQuery } from '../database/database';
import { getSupabase } from './supabase';

/**
 * AuthService - Central de Controle de Autenticação e Sessão 🔐🛡️
 * Fornece métodos unificados para login, logout, verificação de sessão e
 * fluxo de redefinição de senhas com suporte local (SQLite) e remoto (Supabase).
 */
export const AuthService = {
    /**
     * Verifica se existe uma sessão ativa
     */
    checkSession: async () => {
        try {
            const sessionJson = await AsyncStorage.getItem('user_session');
            if (!sessionJson) return null;
            const session = JSON.parse(sessionJson);
            
            return {
                userId: session.id,
                email: session.email || 'produtor@agrogb.com',
                usuario: session.usuario,
                nivel: session.nivel
            };
        } catch (error) {
            console.error('[AuthService] Erro ao checar sessão:', error);
            return null;
        }
    },

    /**
     * Encerra a sessão atual (Opção Nuclear: Destrói todos os caches)
     */
    logout: async () => {
        try {
            await AsyncStorage.removeItem('user_session');
            await SecureStore.deleteItemAsync('agrogb_biometric_credentials').catch(() => {});
            await SecureStore.deleteItemAsync('@user_session').catch(() => {});
            
            const supabase = getSupabase();
            if (supabase) {
                await supabase.auth.signOut();
            }
            return true;
        } catch (error) {
            console.error('[AuthService] Erro ao deslogar:', error);
            return false;
        }
    },

    /**
     * Registra um novo usuário no Supabase Auth e no Banco Local
     */
    registerWithEmail: async (email, password) => {
        try {
            const cleanedEmail = email.trim().toLowerCase();
            const supabase = getSupabase();

            if (!supabase) throw new Error("Supabase não configurado.");

            // 1. Cria apenas a conta no Auth. 
            // A Trigger on_auth_user_created (no Supabase) fará o INSERT automático na tabela profiles.
            const { data, error } = await supabase.auth.signUp({
                email: cleanedEmail,
                password: password,
                options: {
                    data: { role: 'PENDENTE' }
                }
            });

