            // [RBAC Granular - Supreme Architecture] Lê a claim injetada no JWT pelo Auth Hook (Evita query extra O(1))
            const jwtRole = data.user.app_metadata?.role?.toUpperCase();
            const rbacRole = jwtRole || profileData?.role || 'PENDENTE';

            const sessionObj = {
