/**
 * AgroTimelineService
 * 
 * Unifica eventos dispersos em múltiplas tabelas (Plantio, Colheita, Aplicações)
 * em uma única Array Cronológica para montar a Linha do Tempo Visual.
 */
export const AgroTimelineService = {

    /**
     * Busca todos os eventos que ocorreram durante o ciclo de um Plantio específico.
     * @param {string} plantioId - O UUID do Plantio (Ciclo)
     */
    getTimelineByPlantio: async (plantioId) => {
        try {
            const timeline = [];

            // 1. Busca o Evento Origem (O Plantio)
            const resPlantio = await executeQuery(`
                SELECT p.id, p.data_plantio, p.quantidade_sementes, p.espacamento, c.nome as cultura_nome 
                FROM v2_plantios p
                LEFT JOIN v2_culturas c ON c.id = p.cultura_id
                WHERE p.id = ?
            `, [plantioId]);

            if (resPlantio.rows.length > 0) {
                const p = resPlantio.rows.item(0);
                timeline.push({
                    id: `plantio_${p.id}`,
                    type: 'PLANTIO',
                    date: p.data_plantio,
                    title: `Início do Plantio: ${p.cultura_nome || 'Cultura'}`,
                    subtitle: `Qtd: ${p.quantidade_sementes || 0} - Espaçamento: ${p.espacamento || 0}`,
                    icon: 'leaf',
                    color: '#10B981' // Verde Esmeralda
                });
            }

            // 2. Busca Aplicações de Defensivos deste Plantio
            const resAplicacoes = await executeQuery(`
                SELECT id, data_aplicacao, produto_id, dosagem, area_aplicada 
                FROM v2_aplicacoes_defensivos 
                WHERE plantio_id = ?
            `, [plantioId]);

            for (let i = 0; i < resAplicacoes.rows.length; i++) {
                const a = resAplicacoes.rows.item(i);
                timeline.push({
                    id: `aplicacao_${a.id}`,
                    type: 'DEFENSIVO',
                    date: a.data_aplicacao,
                    title: 'Aplicação de Defensivo',
                    subtitle: `Produto ID: ${a.produto_id?.substring(0,8)} | Dose: ${a.dosagem}`,
                    icon: 'flask',
                    color: '#F59E0B' // Amarelo/Laranja
                });
            }

            // 3. Busca Eventos de Colheita
            const resColheitas = await executeQuery(`
                SELECT id, data_colheita, quantidade_total, unidade, qualidade 
                FROM v2_colheitas 
                WHERE plantio_id = ?
            `, [plantioId]);

            for (let i = 0; i < resColheitas.rows.length; i++) {
                const c = resColheitas.rows.item(i);
                timeline.push({
                    id: `colheita_${c.id}`,
                    type: 'COLHEITA',
                    date: c.data_colheita,
                    title: 'Colheita Realizada',
                    subtitle: `Total: ${c.quantidade_total} ${c.unidade} | Qualidade: ${c.qualidade}`,
                    icon: 'tractor',
                    color: '#FBBF24' // Dourado
                });
            }

            // ORDENAÇÃO CRONOLÓGICA (Mais antigo para mais recente)
            timeline.sort((a, b) => {
                const dataA = new Date(a.date).getTime();
                const dataB = new Date(b.date).getTime();
                return dataA - dataB;
            });

            return timeline;

        } catch (error) {
            console.error('[AgroTimelineService] Erro ao buscar timeline:', error);
            throw error;
        }
    },

    /**
     * Busca todos os plantios de um talhão para permitir que o usuário escolha qual ciclo quer ver.
     */
    getPlantiosByTalhao: async (talhaoId) => {
        try {
            const res = await executeQuery(`
                SELECT p.id, p.data_plantio, c.nome as cultura_nome 
                FROM v2_plantios p
                LEFT JOIN v2_culturas c ON c.id = p.cultura_id
                WHERE p.talhao_id = ?
                ORDER BY p.data_plantio DESC
            `, [talhaoId]);

            const plantios = [];
            for (let i = 0; i < res.rows.length; i++) {
                plantios.push(res.rows.item(i));
            }
            return plantios;
        } catch (error) {
            console.error('[AgroTimelineService] Erro ao listar plantios:', error);
            return [];
        }
    },

    /**
     * Helper para popular a interface na primeira vez (já que nem todos os usuários terão todos os dados linkados).
     */
    getAllTalhoes: async () => {
        try {
            const res = await executeQuery(`SELECT id, nome FROM v2_talhoes ORDER BY nome ASC`);
            const talhoes = [];
            for(let i=0; i<res.rows.length; i++) talhoes.push(res.rows.item(i));
            return talhoes;
        } catch(e) {
            return [];
        }
    }
};

import * as Location from 'expo-location';
import AsyncStorage from '@react-native-async-storage/async-storage';
import 'react-native-url-polyfill/auto';

// API Open-Meteo (Sem necessidade de Chave / 100% Gratuita e Confiável)
const BASE_URL = 'https://api.open-meteo.com/v1/forecast';

export const WeatherService = {
    getLocation: async (forceRequest = false) => {
        try {
            let { status } = await Location.getForegroundPermissionsAsync();

            if (status !== 'granted' && forceRequest) {
                const req = await Location.requestForegroundPermissionsAsync();
                status = req.status;
            }

            if (status !== 'granted') return null;

            const location = await Location.getCurrentPositionAsync({ accuracy: Location.Accuracy.Balanced });
            const coords = { lat: location.coords.latitude, lon: location.coords.longitude };
            await AsyncStorage.setItem('user_location', JSON.stringify(coords));
            return coords;
        } catch (error) {
            const cached = await AsyncStorage.getItem('user_location');
            return cached ? JSON.parse(cached) : null;
        }
    },

    getWeather: async (lat, lon) => {
        try {
            // URL da Open-Meteo com Temperatura, Humidade, Vento, Código WMO, Previsão Max/Min diária e Índice UV
            const endpoint = `${BASE_URL}?latitude=${lat}&longitude=${lon}&current_weather=true&hourly=relative_humidity_2m,precipitation_probability,uv_index&daily=temperature_2m_max,temperature_2m_min,weathercode,precipitation_probability_max&timezone=auto`;

            const response = await fetch(endpoint);

            if (!response.ok) {
                console.log('⚠️ Aviso Weather API:', response.status);
                throw new Error('Weather API Error');
            }

            const data = await response.json();
            
            // Dados Atuais
            const current = data.current_weather;
            const temp = Math.round(current.temperature);
            const wind = Math.round(current.windspeed);
            const wmoCode = current.weathercode;
            
            // Humidade (Pegando a humidade da hora atual)
            const hourIndex = new Date().getHours();
            const humidity = data.hourly?.relative_humidity_2m?.[hourIndex] || 50;
            const pop = data.hourly?.precipitation_probability?.[hourIndex] || 0;
            const uv = data.hourly?.uv_index?.[hourIndex] || 0;

            // Previsão Máx e Mín de hoje
            const tempMax = Math.round(data.daily?.temperature_2m_max?.[0] || temp);
            const tempMin = Math.round(data.daily?.temperature_2m_min?.[0] || temp);

            // Mapeando Códigos WMO
            const mapWmoCode = (code) => {
                let description = 'Céu Limpo';
                let iconCode = '01d';
                if (code === 0) { description = 'Céu Limpo'; iconCode = '01d'; }
                else if (code >= 1 && code <= 3) { description = 'Parcialmente Nublado'; iconCode = '02d'; }
                else if (code === 45 || code === 48) { description = 'Neblina'; iconCode = '03d'; }
                else if (code >= 51 && code <= 67) { description = 'Chuva Leve/Moderada'; iconCode = '09d'; }
                else if (code >= 71 && code <= 77) { description = 'Neve'; iconCode = '13d'; }
                else if (code >= 80 && code <= 82) { description = 'Pancadas de Chuva'; iconCode = '10d'; }
                else if (code >= 95) { description = 'Tempestade Elétrica'; iconCode = '11d'; }
                return { description, iconCode };
            };

            const currentWmo = mapWmoCode(wmoCode);

            let alerts = [];
            if (wind > 40) {
                alerts.push({ event: 'Alerta Laranja (Ventos Fortes)', description: 'Rajadas de vento perigosas detectadas.', color: '#F59E0B' }); 
            }
            if (wmoCode >= 95) {
                alerts.push({ event: 'Alerta Vermelho (Tempestade)', description: 'Risco iminente de raios e chuvas intensas.', color: '#EF4444' }); 
            }

            // Mapear 7 dias
            const forecast = [];
            if (data.daily && data.daily.time) {
                for (let i = 0; i < 7; i++) {
                    if (data.daily.time[i]) {
                        const dayWmo = mapWmoCode(data.daily.weathercode?.[i] || 0);
                        forecast.push({
                            date: data.daily.time[i],
                            tempMax: Math.round(data.daily.temperature_2m_max?.[i] || 0),
                            tempMin: Math.round(data.daily.temperature_2m_min?.[i] || 0),
                            pop: data.daily.precipitation_probability_max?.[i] || 0,
                            icon: dayWmo.iconCode,
                            description: dayWmo.description
                        });
                    }
                }
            }

            const weatherData = {
                temp: temp,
                tempMax: tempMax,
                tempMin: tempMin,
                description: currentWmo.description,
                icon: currentWmo.iconCode,
                humidity: humidity,
                wind: wind,
                uv: uv,
                city: 'Fazenda AgroGB', 
                pop: pop,
                alerts: alerts,
                forecast: forecast,
                timestamp: new Date().getTime()
            };

            await AsyncStorage.setItem('weather_cache', JSON.stringify(weatherData));
            return weatherData;
        } catch (error) {
            console.log('❌ Erro Genuíno no Fetch do Clima:', error.message || error);
            const cached = await AsyncStorage.getItem('weather_cache');
            if (cached) return JSON.parse(cached);

            return null; // Força mostrar erro ou recarregar
        }
    }
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { useColorScheme } from 'react-native';
import { getAppSettings, updateAppSetting } from '../database/database';
import { themeLight } from './themeLight';
import { themeDark } from './themeDark';
import { theme as legacyTheme } from './styles/theme';

const ThemeContext = createContext();

export const ThemeProvider = ({ children }) => {
    const systemColorScheme = useColorScheme();
    const [themeConfig, setThemeConfig] = useState('dark'); // FONT: Forçando Dark Slate por padrão
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        loadSettings();
    }, []);

    const loadSettings = async () => {
        try {
            const settings = await getAppSettings();
            if (settings && settings.theme_mode) {
                setThemeConfig(settings.theme_mode);
            }
        } catch (error) {
            console.error('Erro ao carregar configurações de tema:', error);
        } finally {
            setLoading(false);
        }
    };

    const setTheme = async (mode) => {
        try {
            await updateAppSetting('theme_mode', mode);
            setThemeConfig(mode);
        } catch (error) {
            console.error('Erro ao salvar tema:', error);
        }
    };

    const effectiveMode = themeConfig === 'system' 
        ? 'dark' // Fallback forçado para dark
        : themeConfig;
        
    const activeTheme = effectiveMode === 'dark' ? themeDark : themeLight;
    
    // Mesclar temas para manter retrocompatibilidade com telas antigas
    const mergedTheme = {
        ...legacyTheme,
        colors: {
            ...legacyTheme.colors,
            ...activeTheme.colors
        }
    };

    return (
        <ThemeContext.Provider value={{
            theme: mergedTheme,
            themeMode: themeConfig,
            effectiveTheme: effectiveMode,
            colors: mergedTheme.colors,
            setTheme,
            isDark: effectiveMode === 'dark',
            isDarkMode: effectiveMode === 'dark'
        }}>
            {!loading && children}
        </ThemeContext.Provider>
    );
};

export const AVAILABLE_THEMES = [
    { id: 'system', label: 'Sistema', icon: 'settings-outline' },
    { id: 'light', label: 'Claro', icon: 'sunny-outline' },
    { id: 'dark', label: 'Escuro', icon: 'moon-outline' },
];

export const useTheme = () => {
    const context = useContext(ThemeContext);
    if (!context) {
        return {
            theme: { ...legacyTheme, colors: { ...legacyTheme.colors, ...themeDark.colors } },
            effectiveTheme: 'dark',
            colors: { ...legacyTheme.colors, ...themeDark.colors },
            setTheme: () => { },
            isDark: true,
            isDarkMode: true
        };
    }
    return context;
};

